public FormRun parmFormRun(FormRun _formRun = formRun)
{
    formRun = _formRun;

    return formRun;
}

public static void main(Args _args)
{
    if (_args && _args.caller() is FormRun && _args.record())
    {
        FormRun formRun = _args.caller();

        IFRUniversalInterfaceSystemExcludeRecords ifrUniversalInterfaceSystemExcludeRecords = IFRUniversalInterfaceSystemExcludeRecords::construct(formRun);

        ifrUniversalInterfaceSystemExcludeRecords.run();
    }

}

public void run()
{
    MultiSelectionHelper	            multiselectionHelper                = MultiSelectionHelper::createFromCaller(formRun);                    
    IFRUniversalInterfaceSystemTable    ifrUniversalInterfaceSystemTable    = multiselectionHelper.getFirst();

    while (ifrUniversalInterfaceSystemTable)
    {
        if (ifrUniversalInterfaceSystemTable.Status == IFRUniversalInterfaceSystemStatus::Error)
        {
            ttsbegin;
            ifrUniversalInterfaceSystemTable.selectForUpdate(true);

            ifrUniversalInterfaceSystemTable.Status         = IFRUniversalInterfaceSystemStatus::Excluded;
            guid guidNull;
            ifrUniversalInterfaceSystemTable.ExecutionId    = guidNull;


            ifrUniversalInterfaceSystemTable.update();
            ttscommit;
        }

        ifrUniversalInterfaceSystemTable = multiselectionHelper.getNext();
    }
}

public static IFRUniversalInterfaceSystemExcludeRecords construct(FormRun _formRun)
{
    IFRUniversalInterfaceSystemExcludeRecords ifrUniversalInterfaceSystemExcludeRecords = new IFRUniversalInterfaceSystemExcludeRecords();

    ifrUniversalInterfaceSystemExcludeRecords.parmFormRun(_formRun);

    return ifrUniversalInterfaceSystemExcludeRecords;
}
